int Student::totalStudents = 0; // defined ONCE, outside the class

#include <iostream>

using namespace std;

class Student
{
public:
    static int totalStudents;

    Student()
    {
        totalStudents++; // shared counter, incremented by every constructor call
    }
};

int Student::totalStudents = 0;

int main()
{
    Student s1;
    Student s2;
    Student s3;

    cout << Student::totalStudents << endl;

    return 0;
}

class Student
{
public:
    static int totalStudents;

    static int getTotalStudents() // static member function
    {
        return totalStudents;
    }
};

cout << Student::getTotalStudents(); // called directly on the CLASS, no object needed

#include <iostream>

using namespace std;

void trackCalls()
{
    static int callCount = 0; // initialized ONCE, ever
    callCount++;
    cout << "Called " << callCount << " time(s)" << endl;
}

int main()
{
    trackCalls();
    trackCalls();
    trackCalls();

    return 0;
}

